prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT
  ?task ?taskName
  (COUNT(DISTINCT ?msg) AS ?relatedMessageCount)
WHERE {
  ?model a bboExt:Model .
  FILTER(tai:normalizedId = "1cd93309017949fdbebf0f7d7ea50b4a")

  ?task a bboExt:ChoreographyTask ;
        tai:belongsTo ?choreo .
  ?task bbo:name ?taskName .

  OPTIONAL {
    ?mf a bboExt:MessageFlow ;
        tai:belongsTo ?choreo .

    ?mf bboExt:messageRef ?msg .

    FILTER(
      (EXISTS {
        FILTER(STRENDS(STR(?task), ?srcTaskId))
        BIND(?mf bboExt:sourceRef AS ?srcTaskId)
      }) ||
      (EXISTS {
        FILTER(STRENDS(STR(?task), ?tgtTaskId))
        BIND(?mf bboExt:targetRef AS ?tgtTaskId)
      })
    )
  }

  FILTER(BOUND(?mf))
}
GROUP BY ?task ?taskName
HAVING(COUNT(DISTINCT ?msg) = 2)
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT
  ?task
  ?taskName
  (COUNT(DISTINCT ?msg) AS ?relatedMessageCount)
WHERE {
  ?model a bboExt:Model .
  FILTER(tai:normalizedId = "1cd93309017949fdbebf0f7d7ea50b4a")

  ?task a bboExt:ChoreographyTask ;
        tai:belongsTo ?choreo .
  ?task bbo:name ?taskName .

  {
    ?mf a bboExt:MessageFlow ;
        tai:belongsTo ?choreo ;
        bboExt:sourceRef ?taskId ;
        bboExt:messageRef ?msg .
    FILTER(STRENDS(STR(?task), ?taskId))
  }
  UNION
  {
    ?mf a bboExt:MessageFlow ;
        tai:belongsTo ?choreo ;
        bboExt:targetRef ?taskId ;
        bboExt:messageRef ?msg .
    FILTER(STRENDS(STR(?task), ?taskId))
  }
}
GROUP BY ?task ?taskName
HAVING(COUNT(DISTINCT ?msg) = 2)
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT
  ?mf
  ?mfName
  ?sourceRef
  ?targetRef
  ?msgRef
WHERE {
  ?model a bboExt:Model .
  FILTER(tai:normalizedId = "1cd93309017949fdbebf0f7d7ea50b4a")

  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?defs .
  ?defs tai:belongsTo ?model .

  ?mf a bboExt:MessageFlow ;
      tai:belongsTo ?choreo .

  OPTIONAL { ?mf bbo:name ?mfName . }
  OPTIONAL { ?mf bboExt:sourceRef ?sourceRef . }
  OPTIONAL { ?mf bboExt:targetRef ?targetRef . }
  OPTIONAL { ?mf bboExt:messageRef ?msgRef . }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT
  ?mf
  ?mfName
  ?model
  (COALESCE(?modelId, STR(?model)) AS ?modelId)
WHERE {
  ?mf a bboExt:MessageFlow ;
      tai:belongsTo ?scope .

  ?scope (tai:belongsTo)* ?model .
  ?model a bboExt:Model .
  OPTIONAL { ?model tai:normalizedId ?modelId . }

  FILTER(
    ?modelId = "1cd93309017949fdbebf0f7d7ea50b4a" ||
    EXISTS { ?model tai:originalId "1cd93309017949fdbebf0f7d7ea50b4a" }
  )

  OPTIONAL { ?mf bbo:name ?mfName . }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT
  ?task
  ?taskName
  (COUNT(DISTINCT ?mf) AS ?messageFlowCount)
  (COUNT(DISTINCT ?msg) AS ?distinctMessageCount)
WHERE {
  ?model a bboExt:Model .
  FILTER(tai:normalizedId = "sid_b7b36685_2b15_4bc0_8853_27012da21b61")

  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?defs .
  ?defs tai:belongsTo ?model .

  ?task a bboExt:ChoreographyTask ;
        tai:belongsTo ?choreo ;
        bbo:name ?taskName .

  ?mf a bboExt:MessageFlow ;
      tai:belongsTo ?choreo .

  OPTIONAL {
    ?mf bboExt:messageRef ?msg .
  }

  FILTER(
    STRENDS(STR(?task), ?s) || STRENDS(STR(?task), ?t)
  )

  # bind potential source/target refs if they exist
  OPTIONAL { BIND(?mf AS ?dummy) BIND(STR(?dummy) AS ?s) }
}
GROUP BY ?task ?taskName
LIMIT 25
